'use client';

import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

export default function WhatIBuild() {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedTech, setSelectedTech] = useState('All');
  const [dropdownOpen, setDropdownOpen] = useState(false);

  const projects = [
    {
      title: "Relationship Tracker",
      description: "A Next.js app for tracking relationships with timeline logging, interaction analytics, and a fully responsive UI architecture.",
      tags: ["Next.js", "React", "TailwindCSS", "Node.js", "MongoDB"],
      link: "#", // Clickable link to be edited by user later
      gradient: "from-blue-400 to-indigo-500"
    },
    {
      title: "Book Library SPA",
      description: "A React SPA with client-side routing and state-driven book list management — readlist, wishlist, and purchases — with dynamic sorting and filtering.",
      tags: ["React", "Vanilla JS", "TailwindCSS", "REST APIs"],
      link: "#", // Clickable link to be edited by user later
      gradient: "from-purple-400 to-pink-500"
    },
    {
      title: "News Platform",
      description: "A modern Next.js news platform with category-based browsing, dynamic article views, and secure authentication for personalized access.",
      tags: ["Next.js", "React", "TailwindCSS", "REST APIs", "Node.js"],
      link: "#", // Clickable link to be edited by user later
      gradient: "from-emerald-400 to-teal-500"
    },
    {
      title: "Pulse Wire",
      description: "A responsive GitHub Issues tracking dashboard built with Vanilla JS and REST APIs — featuring filtering, search, modal views, and dynamic status indicators.",
      tags: ["Vanilla JS", "REST APIs", "TailwindCSS"],
      link: "#", // Clickable link to be edited by user later
      gradient: "from-rose-400 to-orange-500"
    },
    {
      title: "ToolNest",
      description: "A modern digital tools marketplace built with React — featuring dynamic product browsing, cart management, and a clean responsive UI.",
      tags: ["React", "TailwindCSS", "REST APIs"],
      link: "#", // Clickable link to be edited by user later
      gradient: "from-cyan-400 to-blue-500"
    },
    {
      title: "Robust Bengali Speech Recognition",
      description: "Comprehensive research project on Bengali speech recognition using the OOD-Speech dataset, achieving 76% relative WER reduction. Built interactive demos with Gradio and FastAPI.",
      tags: ["PyTorch", "Transformers", "Deep Learning", "FastAPI", "AI"],
      link: "#", // Clickable link to be edited by user later
      gradient: "from-sky-400 to-indigo-600"
    }
  ];

  // Dynamically extract unique technologies for filter list
  const allTags = projects.reduce((acc, proj) => {
    proj.tags.forEach(tag => {
      if (!acc.includes(tag)) acc.push(tag);
    });
    return acc;
  }, []);
  const uniqueTechnologies = ['All', ...allTags.sort()];

  // Filter projects by both search query and active dropdown tag
  const filteredProjects = projects.filter(project => {
    const matchesSearch = project.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
                          project.description.toLowerCase().includes(searchQuery.toLowerCase()) ||
                          project.tags.some(tag => tag.toLowerCase().includes(searchQuery.toLowerCase()));
    const matchesTech = selectedTech === 'All' || project.tags.includes(selectedTech);
    return matchesSearch && matchesTech;
  });

  const gridVars = {
    initial: {},
    animate: {
      transition: {
        staggerChildren: 0.08,
      }
    }
  };

  const cardVars = {
    initial: { opacity: 0, scale: 0.95, y: 30 },
    animate: { 
      opacity: 1, 
      scale: 1, 
      y: 0, 
      transition: { type: "spring", stiffness: 60, damping: 14 } 
    },
    exit: { opacity: 0, scale: 0.95, y: 15, transition: { duration: 0.2 } }
  };

  return (
    <section id="what-i-build" className="relative w-full bg-white py-24 px-6 border-t border-slate-100 overflow-hidden flex flex-col items-center">
      {/* Background radial soft pattern */}
      <div className="absolute inset-0 bg-[linear-gradient(to_right,#f1f5f9_1px,transparent_1px),linear-gradient(to_bottom,#f1f5f9_1px,transparent_1px)] bg-[size:4rem_4rem] [mask-image:radial-gradient(ellipse_60%_50%_at_50%_0%,#000_70%,transparent_100%)] opacity-35 pointer-events-none"></div>

      <div className="max-w-6xl w-full mx-auto relative z-10 flex flex-col items-center">
        {/* Header */}
        <div className="text-center max-w-xl">
          <h2 className="font-extrabold text-4xl text-slate-950 tracking-tight">
            My Projects
          </h2>
          <p className="text-slate-500 font-medium text-base md:text-lg mt-3">
            Projects I worked on. Each of them containing its own case study.
          </p>
        </div>

        {/* Live Search Bar */}
        <div className="w-full max-w-xl relative mt-10">
          <div className="absolute inset-y-0 left-0 pl-3.5 flex items-center pointer-events-none">
            <svg className="h-5 w-5 text-slate-400" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
            </svg>
          </div>
          <input
            type="text"
            placeholder="Search projects by name, description, or technology..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full pl-11 pr-4 py-3 rounded-lg border border-slate-200/80 bg-white placeholder-slate-400 text-slate-900 focus:outline-none focus:border-slate-400 focus:ring-1 focus:ring-slate-400 transition-all text-sm shadow-sm"
          />
        </div>

        {/* Dynamic Category Dropdown Filter */}
        <div className="relative mt-5 self-center md:self-start md:ml-10 z-30">
          <button 
            onClick={() => setDropdownOpen(!dropdownOpen)}
            className="flex items-center gap-1.5 text-slate-500 hover:text-slate-800 transition-colors text-sm font-semibold cursor-pointer"
          >
            Filter by technology: <span className="text-slate-950 font-bold">{selectedTech}</span>
            <svg className={`w-4 h-4 transition-transform duration-200 ${dropdownOpen ? 'rotate-180' : ''}`} fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" d="M19.5 8.25l-7.5 7.5-7.5-7.5" />
            </svg>
          </button>
          
          <AnimatePresence>
            {dropdownOpen && (
              <motion.div 
                initial={{ opacity: 0, y: -10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -10 }}
                className="absolute left-0 mt-2 w-48 bg-white border border-slate-100 rounded-lg shadow-lg py-1 z-40 max-h-60 overflow-y-auto"
              >
                {uniqueTechnologies.map((tech) => (
                  <button
                    key={tech}
                    onClick={() => {
                      setSelectedTech(tech);
                      setDropdownOpen(false);
                    }}
                    className={`w-full text-left px-4 py-2 text-xs font-semibold hover:bg-slate-50 transition-colors ${
                      selectedTech === tech ? 'text-[#D9265F]' : 'text-slate-600'
                    }`}
                  >
                    {tech}
                  </button>
                ))}
              </motion.div>
            )}
          </AnimatePresence>
        </div>

        {/* Projects Card Grid (cols-3) */}
        <motion.div 
          variants={gridVars}
          initial="initial"
          whileInView="animate"
          viewport={{ once: true, margin: "-50px" }}
          className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 mt-12 w-full"
        >
          <AnimatePresence mode="popLayout">
            {filteredProjects.map((project, idx) => (
              <motion.a
                key={project.title}
                href={project.link}
                variants={cardVars}
                layout
                className="group block bg-white border border-slate-100 rounded-2xl overflow-hidden shadow-[0_4px_25px_-4px_rgba(0,0,0,0.01),0_10px_15px_-3px_rgba(0,0,0,0.02)] hover:shadow-[0_15px_35px_-5px_rgba(0,0,0,0.04),0_10px_15px_-6px_rgba(0,0,0,0.04)] hover:border-slate-200/80 hover:-translate-y-1 transition-all duration-300 flex flex-col cursor-pointer"
              >
                {/* Visual Placeholder Banner (Styish Gradient) */}
                <div className={`w-full aspect-[16/10] bg-gradient-to-br ${project.gradient} flex items-center justify-center p-6 relative overflow-hidden`}>
                  {/* Subtle inner card overlay graphic */}
                  <div className="absolute inset-0 bg-white/5 opacity-0 group-hover:opacity-100 transition-opacity duration-300"></div>
                  
                  {/* Placeholder label */}
                  <span className="text-white/90 font-extrabold text-sm md:text-base uppercase tracking-wider text-center drop-shadow-sm select-none">
                    {project.title}
                  </span>
                </div>

                {/* Card Text Content */}
                <div className="p-6 flex flex-col flex-grow">
                  <h3 className="font-extrabold text-slate-950 text-[17px] tracking-tight group-hover:text-[#D9265F] transition-colors leading-tight">
                    {project.title}
                  </h3>
                  <p className="text-slate-500 font-medium text-xs md:text-sm mt-3 leading-relaxed flex-grow">
                    {project.description}
                  </p>

                  {/* Tech stack tags */}
                  <div className="flex flex-wrap gap-2 mt-6">
                    {project.tags.map((tag, tIdx) => (
                      <span 
                        key={tIdx} 
                        className="border border-slate-200 bg-white px-2.5 py-1 rounded-full text-[11px] font-bold text-slate-600 shadow-sm"
                      >
                        {tag}
                      </span>
                    ))}
                  </div>
                </div>
              </motion.a>
            ))}
          </AnimatePresence>
        </motion.div>
      </div>
    </section>
  );
}